var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":null,"text":{"KOREA":"20여 년 전, 관리실패라는 거대한 재해가 일어났다.","JPN":"約20年前、管理失敗という巨大な災害が発生した。","ENG":"20 years ago, a colossal disaster called Administration Failure occurred.","TWN":"二十年前，發生過一場管理失敗的巨大災難。"},"stage":{"bg":"SUMMER_BEACH_NIGHT","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":null,"text":{"KOREA":"많은 사람이 죽었고, 많은 터전이 사라졌다고 한다.","JPN":"多くの人が命を落とし、多くの家屋が消えたという。","ENG":"Many people died, and many more lost their homes.","TWN":"據說，當時很多人死掉，大片的房屋被損毀。"},"stage":{"bg":"SUMMER_BEACH_NIGHT","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":null,"text":{"KOREA":"바닷가의 사람들도 예외는 아니었다.","JPN":"海辺の人々も例外ではなかった。","ENG":"People near the sea were no exception.","TWN":"連海邊的人們也不例外。"},"stage":{"bg":"FRONTBAY_DECK_FOG","slots":{"L":null,"C":null,"R":null}}},{"id":"L7_1","type":"dialog","speaker":null,"text":{"KOREA":"문명의 잔해 위에 남겨진 생존자들에게 법은 무색했고, 그 사이에선 범죄가 아무렇지 않게 일어났다.","JPN":"文明の残骸の上に残された生存者に法は存在価値をなくし、その狭間では犯罪が蔓延っていた。","ENG":"Law became meaningless for the survivors standing on the rubble of civilization, with criminal activity happening all throughout.","TWN":"對於被遺留在文明廢墟上的倖存者而言，法律形同虛設，在那段時期裡，犯罪不會受到任何應有的懲罰。"},"stage":{"bg":"FRONTBAY_DECK_FOG","slots":{"L":null,"C":null,"R":null}}},{"id":"L8_1","type":"dialog","speaker":null,"text":{"KOREA":"그중 대부분은 가진 자의 것을 훔치는 범죄가 아닌, 서로의 생존권을 건 빈자들의 싸움이었다.","JPN":"そのほとんどは富める者から盗む犯罪ではなく、互いの生存権をかけた貧しい者たちの戦いだった。","ENG":"However, most of the crimes were not about stealing from the rich, but about the poor fighting for their lives.","TWN":"其中大部分的犯罪，不是劫富濟貧，而是窮人之間為生存而發生的鬥爭。"},"stage":{"bg":"FRONTBAY_DECK_FOG","slots":{"L":null,"C":null,"R":null}}},{"id":"L9_1","type":"dialog","speaker":null,"text":{"KOREA":"그 처절한 싸움을 처음으로 중재했던 건, 정부도, 관리국도 아닌…","JPN":"その凄絶な戦いを最初に仲裁したのは、政府でも管理局でもなく……","ENG":"The first to intervene and mediate the fights was not the government nor the Administration...","TWN":"然而平息那場慘烈鬥爭的，既不是政府，也不是管理局…"},"stage":{"bg":"FRONTBAY_DECK_FOG","slots":{"L":null,"C":null,"R":null}}},{"id":"L12_1","type":"dialog","speaker":null,"text":{"KOREA":"바다의 무법자들이었다.","JPN":"海の無法者たちだった。","ENG":"But the outlaws of the sea.","TWN":"而是一群海上的不法之徒。"},"stage":{"bg":"FRONTBAY_03","slots":{"L":null,"C":null,"R":null}}},{"id":"L13_1","type":"dialog","speaker":null,"text":{"KOREA":"더 이상 훔칠 게 아무것도 남지 않은 해적은 누구도 원치 않는 바다로 나아가 침식체들을 사냥하기 시작했다.","JPN":"もう盗むものが何も残っていなかった海賊は、誰もが好まない海に出て侵食体を狩り始めた。","ENG":"Once there was nothing left to steal on land, the pirates set sail for the seas that no one wanted to traverse and started hunting C.O.s.","TWN":"偷無可偷的海盜們，揚帆出航，去到無人願意踏足的大海之上，展開狩獵侵蝕體的日子。"},"stage":{"bg":"FRONTBAY_03","slots":{"L":null,"C":null,"R":null}}},{"id":"L14_1","type":"dialog","speaker":null,"text":{"KOREA":"그 대가로 사람들에게 보호비를 받았지만, 사람들은 침식체의 위협으로부터 벗어난 삶을 되찾기 위해 마땅한 대가를 치렀다.","JPN":"その対価として人々から保護費をもらったが、人々は侵食体の脅威から逃れた暮らしを取り戻すため、それ相応の対価を払った。","ENG":"In return for their services, these pirates collected protection fees, which the people gladly paid to reclaim their lives from the threats of C.O.s.","TWN":"雖然他們因此向大家索討保護費作為回報。但只要能免於受到侵蝕體的威脅，人們也不在乎這一點代價。"},"stage":{"bg":"FRONTBAY_03","slots":{"L":null,"C":null,"R":null}}},{"id":"L15_1","type":"dialog","speaker":null,"text":{"KOREA":"잃어버린 고향을 점차 수복하기 시작하면서, 사람들은 내일이라는 희망을 품게 되었다.","JPN":"次第に失った故郷が修復し始め、人々は明日という希望を抱くようになった。","ENG":"As the ruins of their hometown were gradually reconstructed, the people started becoming hopeful for a brighter tomorrow.","TWN":"隨著人們逐漸開始重建失去的家園，他們開始對明天充滿希望。"},"stage":{"bg":"FRONTBAY_03","slots":{"L":null,"C":null,"R":null}}},{"id":"L16_1","type":"dialog","speaker":null,"text":{"KOREA":"해적이 권력을 갖게 되면서, 자연스레 범죄자들은 권력의 통제를 따르기 시작했다.","JPN":"海賊が権力を持つようになり、自然と犯罪者たちは権力の統制に従い始めた。","ENG":"Also, the pirates began gaining power, and the rest of the criminals submitted under their control.","TWN":"海盜得勢後，罪犯自然也開始屈服於他們。"},"stage":{"bg":"FRONTBAY_03","slots":{"L":null,"C":null,"R":null}}},{"id":"L17_1","type":"dialog","speaker":null,"text":{"KOREA":"대균열 이후 무너졌던 질서가 돌아오기 시작한 것이다.","JPN":"大亀裂以後、崩れた秩序が戻りつつあったのだ。","ENG":"The order that collapsed after the Grand Dimension Crevice was being restored.","TWN":"大峽谷之後，曾經瓦解的秩序開始回到正軌。"},"stage":{"bg":"FRONTBAY_03","slots":{"L":null,"C":null,"R":null}}},{"id":"L18_1","type":"dialog","speaker":null,"text":{"KOREA":"아이러니하게도 그 질서의 중심에는 해적이 있었다.","JPN":"皮肉にも、その秩序の中心には海賊がいた。","ENG":"And the irony behind it was that a pirate was at the core of this so-called order.","TWN":"諷刺的是，這個秩序的核心是一名海盜。"},"stage":{"bg":"FRONTBAY_03","slots":{"L":null,"C":null,"R":null}}},{"id":"L19_1","type":"dialog","speaker":null,"text":{"KOREA":"사람들은 그 해적의 이름을 기꺼이 존경하며, 이렇게 불렀다.","JPN":"人々はその海賊の名前を喜んで尊敬し、こう呼んだ。","ENG":"The people willingly respected this pirate's name and called him...","TWN":"人們尊敬欽佩他，尊敬地稱呼他為，"},"stage":{"bg":"FRONTBAY_03","slots":{"L":null,"C":null,"R":null}}},{"id":"L20_1","type":"dialog","speaker":null,"text":{"KOREA":"대해적. 에이버리.","JPN":"大海賊、エイバリー。","ENG":"The Great Pirate, Avery.","TWN":"大海盜艾維利。"},"stage":{"bg":"FRONTBAY_03","slots":{"L":null,"C":null,"R":null}}},{"id":"L23_1","type":"dialog","speaker":null,"text":{"KOREA":"들리시나요? 듣고 계시면 대답해주세요. 시니어님!","JPN":"聞こえますか？　聞いているのなら、答えてください。シニア様！","ENG":"Do you copy? Sir, please answer if you can hear me!","TWN":"聽得到嗎？聽到請回答，Senior！"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L25_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ffd34c>그래, 날 찾았나?</color>","JPN":"<color=#ffd34c>ああ、私を呼んだか？</color>","ENG":"<color=#ffd34c>I hear you. You're looking for me?</color>","TWN":"<color=#ffd34c>嗯，你找我？</color>"},"stage":{"bg":"DOCK_CLOUDY","slots":{"L":null,"C":null,"R":null}}},{"id":"L26_1","type":"dialog","speaker":"SECRETARY_FRONTBAY_NULL_ADMIN","text":{"KOREA":"대체 어디 계신 건가요? 며칠째 자릴 비우시고, 소식도 없고!","JPN":"いったいどこにいるのですか？　何日も不在で、何の連絡もないなんて！","ENG":"Where are you? You have been gone for days without sending any word!","TWN":"你到底跑去哪裡？消失這麼多天，一點消息都沒有！"},"stage":{"bg":"DOCK_CLOUDY","slots":{"L":null,"C":{"char_id":"SECRETARY_FRONTBAY_NULL_ADMIN","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"SECRETARY_FRONTBAY_NULL_ADMIN","text":{"KOREA":"방금 이 통신라인을 찾으려고 제가 전산추적기능을 얼마나 낭비했는지 아세요?!","JPN":"この通信ラインを探すのに、私がどれだけのトラッキング機能を無駄にしたかわかりますか！？","ENG":"Do you know how much of my computer tracking function was wasted trying to find this comms line?!","TWN":"你知道為了找到這條通訊線路，耗費多少電腦追蹤的功能嗎？"},"stage":{"bg":"DOCK_CLOUDY","slots":{"L":null,"C":{"char_id":"SECRETARY_FRONTBAY_NULL_ADMIN","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"SECRETARY_FRONTBAY_NULL_ADMIN","text":{"KOREA":"지금 프론트베이에 어떤 일이 벌어지고 있는지 아시냐고요!","JPN":"今フロントベイに何が起きているのか、わかっているのですか！","ENG":"Are you even aware of what is happening in Front Bay right now?!","TWN":"你知道現在前灣發生什麼事嗎？"},"stage":{"bg":"DOCK_CLOUDY","slots":{"L":null,"C":{"char_id":"SECRETARY_FRONTBAY_NULL_ADMIN","face":"UNIT_HATE"},"R":null}}}]`);export{e as default};